mapper.select:
SELECT

FROM alert_action
WHERE tenant_id = #{tenantId}
  AND id = #{id}

SELECT

FROM alert_action
WHERE tenant_id = #{tenantId}
  AND alert_id = #{alertId}
ORDER BY id DESC

mapper.update:
UPDATE alert_action
SET alert_id = #{alertId},
    action_type = #{actionType},
    action_by = #{actionBy},
    action_note = #{actionNote}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
DELETE
FROM alert_action
WHERE tenant_id = #{tenantId}
  AND id = #{id}
